+    let (idx, loss) = argmin_expected_loss(&actions, &Regime::Resize, |a, s| {
+        LOSS_MATRIX[regime_index(*s)][action_index(*a)]
+    })
+    .unwrap();
+    assert_eq!(idx, 2);
+    assert!((loss - 1.0).abs() < 1e-10);
+}
