+
+    let phases: &[(Regime, u64)] = &[
+        (Regime::Stable, 150),
+        (Regime::Bursty, 150),
+        (Regime::Resize, 150),
+        (Regime::Degraded, 150),
+    ];
+
+    for &(regime, count) in phases {
+        run_frames(&mut ctrl, &mut ledger, regime, count, frame, &mut logs);
+        frame += count;
+    }
+
+    assert_eq!(logs.len(), 600);
+    assert_eq!(ledger.len(), 600);
+    assert_eq!(ledger.total_recorded(), 600);
