+    assert!(
+        non_optimal.is_empty(),
+        "Found {} non-optimal decisions",
+        non_optimal.len(),
+    );
+
+    // All posteriors sum to 1.
+    for log in &logs {
+        assert!(log.posterior.sums_to_one());
+    }
+
+    // Domain count matches.
+    assert_eq!(ledger.domain_count(DecisionDomain::DiffStrategy), 600,);
